import{_ as c,C as h,o as i,c as u,a0 as r,b as s,w as e,a as t,E as l,a1 as d,j as n}from"./chunks/framework.BjpW4enL.js";const C=JSON.parse('{"title":"AgentSecOps Playground","description":"","frontmatter":{},"headers":[],"relativePath":"projects/agentsecops-playground.md","filePath":"projects/agentsecops-playground.md"}'),g={name:"projects/agentsecops-playground.md"};function p(b,a,m,A,k,y){const o=h("Mermaid");return i(),u("div",null,[a[2]||(a[2]=r('<h1 id="agentsecops-playground" tabindex="-1">AgentSecOps Playground <a class="header-anchor" href="#agentsecops-playground" aria-label="Permalink to &quot;AgentSecOps Playground&quot;">​</a></h1><p>AI 에이전트가 자율적으로 생성한 코드를 안전하게 격리 구동하고, 실행 시 발생하는 비인가 시스템 호출 및 파일 변경 등의 보안 위협 행위를 실시간 모니터링하기 위한 가상 샌드박스입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>Experimental</code></li><li><strong>저장소 주소</strong>: <a href="https://github.com/devcy0922/agentsecops-playground" target="_blank" rel="noreferrer">GitHub (devcy0922/agentsecops-playground)</a></li><li><strong>라이선스</strong>: MIT</li><li><strong>주요 언어</strong>: Go, Python</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>AI 코딩 어시스턴트나 자율 에이전트(Autonomous Agent)가 코드를 수정하고 터미널에서 직접 실행할 때, 악성 패키지가 다운로드되거나 중요 시스템 설정 파일(<code>/etc/passwd</code> 등)을 탈취하려 하거나, 로컬 저장소 전체를 지우는 명령어를 임의 생성할 위험이 존재합니다. 호스트 시스템의 안전을 보장하기 어려운 상태에서 자율 에이전트의 코드 실행 권한을 줄 수 없습니다.</p><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>에이전트가 임의의 쉘 명령 및 프로그램 코드를 실행할 수 있는 독립된 Docker/gVisor 샌드박스를 제공하고, 커널 수준의 이벤트 모니터링(eBPF)을 결합해 비인가 시스템 호출을 감지하여 실시간으로 실행을 제어하고 감사 로그를 남기기 위해 구축했습니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li>gVisor 커널 격리 기반의 임시 일회성(Disposable) 컨테이너 생성 및 파괴</li><li>에이전트 코드 실행 시 eBPF 프로브를 통한 파일 쓰기, 네트워크 소켓 오픈 감시</li><li>보안 가이드라인 위반 호출 감지 시 실시간 프로세스 강제 킬(Kill) 및 차단 정책 적용</li><li>보안 위협 행위 로그를 관제 대시보드 형식으로 수집</li></ul><hr><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',13)),(i(),s(d,null,{default:e(()=>[l(o,{id:"mermaid-73",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20Agent%5B%22AI%20Agent%20Execution%20Signal%22%5D%20--%3E%7C1.%20Run%20Command%7C%20Sandbox%5B%22Sandbox%20Manager%20(Go)%22%5D%0A%20%20%20%20Sandbox%20--%3E%7C2.%20Spawn%20container%7C%20gVisor%5B%22gVisor%20Isolated%20Kernel%22%5D%0A%20%20%20%20subgraph%20Isolated_Env%20%5B%22Runtime%20Sandbox%22%5D%0A%20%20%20%20%20%20%20%20gVisor%20--%3E%20Container%5B%22User%20Code%20%2F%20Commands%22%5D%0A%20%20%20%20end%0A%20%20%20%20Container%20-.-%3E%7C3.%20System%20Calls%7C%20Kernel%5B%22Host%20OS%20Kernel%22%5D%0A%20%20%20%20Kernel%20--%3E%7CeBPF%20Probe%20Hook%7C%20Monitor%5B%22eBPF%20Security%20Monitor%20(C%2FGo)%22%5D%0A%20%20%20%20Monitor%20--%3E%7C4.%20Detect%20Policy%20Violation%7C%20Sandbox%0A%20%20%20%20Sandbox%20--%3E%7CForce%20Terminate%7C%20Container%0A"})]),fallback:e(()=>[...a[0]||(a[0]=[t(" Loading... ",-1)])]),_:1})),a[3]||(a[3]=n("hr",null,null,-1)),a[4]||(a[4]=n("h2",{id:"_5-data-flow",tabindex:"-1"},[t("5. Data Flow "),n("a",{class:"header-anchor",href:"#_5-data-flow","aria-label":'Permalink to "5. Data Flow"'},"​")],-1)),(i(),s(d,null,{default:e(()=>[l(o,{id:"mermaid-78",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Agent%20as%20AI%20Agent%0A%20%20%20%20participant%20Manager%20as%20Sandbox%20Manager%0A%20%20%20%20participant%20gVisor%20as%20gVisor%20Runtime%0A%20%20%20%20participant%20Kernel%20as%20Host%20Kernel%0A%20%20%20%20participant%20Monitor%20as%20eBPF%20Monitor%0A%0A%20%20%20%20Agent-%3E%3EManager%3A%20Execute%20(command%3A%20'curl%20http%3A%2F%2Fmalicious.url')%0A%20%20%20%20Manager-%3E%3EgVisor%3A%20Create%20lightweight%20runsc%20sandbox%0A%20%20%20%20Manager-%3E%3EgVisor%3A%20Launch%20command%20within%20container%0A%20%20%20%20gVisor-%3E%3EKernel%3A%20System%20call%20(SYS_SOCKET)%0A%20%20%20%20Kernel-%3E%3EMonitor%3A%20Trigger%20syscall%20probe%0A%20%20%20%20Monitor-%3E%3EMonitor%3A%20Evaluate%20policy%20(Strict%20deny%20network%20outbound)%0A%20%20%20%20alt%20Outbound%20Blocked%0A%20%20%20%20%20%20%20%20Monitor-%3E%3EManager%3A%20Security%20Threat%20Alert%0A%20%20%20%20%20%20%20%20Manager-%3E%3EgVisor%3A%20SIGKILL%20container%20process%0A%20%20%20%20%20%20%20%20Manager--%3E%3EAgent%3A%20403%20Forbidden%20(Blocked%3A%20Network%20access%20denied)%0A%20%20%20%20end%0A"})]),fallback:e(()=>[...a[1]||(a[1]=[t(" Loading... ",-1)])]),_:1})),a[5]||(a[5]=r(`<hr><h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><ul><li><strong>gVisor(runsc) 도입</strong>: 표준 Docker(runc)가 공유 커널 취약점에 노출되는 것에 대비해, 커널 시스템 호출을 유저 스페이스에서 한 단계 필터링하여 에뮬레이션해주는 gVisor를 샌드박스 기반으로 선정했습니다.</li><li><strong>eBPF 기반 무중단 수집</strong>: 컨테이너 내부 런타임을 수정하지 않고, 호스트 레벨에서 투명하게 비인가 시스템 콜을 낚아채 오버헤드를 최소화하고 에이전트의 우회 시도를 완전히 원천 차단했습니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><ul><li>제로 트러스트 기조에 따라 샌드박스 내부의 아웃바운드 인터넷 연결을 기본적으로 차단(<code>default-deny</code>)하며, 사전 승인된 도메인(예: GitHub API, PyPI 미러)만 화이트리스트 접근을 허용합니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li>실시간으로 비인가 파일 접근 차단 건수 및 네트워크 탈취 시도 이벤트를 JSONL 형식으로 비동기 영속화하여 감사용 로그로 기록합니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>Sandbox</strong>: gVisor (runsc), Docker</li><li><strong>Monitoring</strong>: eBPF, Cilium/ebpf library, Go</li><li><strong>Control Interface</strong>: Python, FastAPI</li></ul><hr><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><p>gVisor 환경이 구성된 로컬 장비에서 샌드박스 관리 서버를 구동합니다.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># gVisor(runsc) 런타임 활성화 상태에서 샌드박스 모니터 가동</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox-mgr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./cmd/main.go</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./sandbox-mgr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> configs/policy.json</span></span></code></pre></div><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>eBPF 커널 레벨의 모니터링은 호스트 리눅스 환경에서만 완벽히 지원되며, macOS 가상화 레이어 아래에서는 정상적인 eBPF 시스템콜 프로브 수집에 제약이 있습니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>샌드박스 환경 내부에서 모니터링한 데이터를 시각화해주는 실시간 웹 터미널 보안 대시보드 추가.</li></ul>`,17))])}const S=c(g,[["render",p]]);export{C as __pageData,S as default};
